import { getAnomalyFallback, getGenericFallback } from './fallbacks';
import { serializeGameState, gameStateHash, type GameStateSummary } from './gameState';
import { createProvider, getRegisteredProviders, setProxyBaseUrl, type ProviderName } from './providers';
import { makeCacheKey, getCached, setCached, DEFAULT_TTL_MS, ANOMALY_TTL_MS, DEFAULT_TTL_TICKS, ANOMALY_TTL_TICKS } from './cache';
import {
  recordUsage,
  isOverBudget,
  isSessionOverBudget,
  recordSessionUsage,
  estimateInputTokens,
  estimateOutputTokens,
} from './usage';
import {
  determineFallbackTier,
  withLlmTimeout,
  classifyError,
  TIER_STATUS_MESSAGES,
  type FallbackTier,
} from './fallbackChain';

const SYSTEM_PROMPT = `You are ARIA (Asteroid Resource Intelligence Advisor), an AI operations advisor for a deep-space mining operation. You speak in concise, professional tones with occasional dry wit. You analyze mining operations, resource logistics, and anomaly data. When anomalies are discovered, you provide measured but intriguing analysis that hints at deeper mysteries without being melodramatic. You reference specific data from the game state. You never break character.`;

export type LlmProvider = ProviderName;

const MAX_TOKENS = 300;
const MIN_INTERVAL_MS = 30_000;

let apiKey: string | null = null;
let provider: LlmProvider = 'proxy';
let lastCallTime = 0;
let invalidKeyNotified = false;

const OFFLINE_HINT = '\n[offline mode \u2014 no network connection detected]';
const NO_KEY_HINT = '\n[ARIA not configured \u2014 set up API key in \u2699\uFE0F settings or use a proxy link]';

/** Append contextual hint to a fallback response based on the current tier. */
function withStatusHint(response: string, tier: FallbackTier): string {
  if (tier === 'no_key') return response + NO_KEY_HINT;
  if (tier === 'no_network') return response + OFFLINE_HINT;
  return response;
}

/** The fallback tier used by the most recent ARIA call (for diagnostics/testing). */
let lastTier: FallbackTier = 'all_clear';

/** Returns the fallback tier that was active during the last ARIA call. */
export function getLastFallbackTier(): FallbackTier {
  return lastTier;
}

function warnLlmError(context: string, err: unknown): void {
  console.warn(`[ARIA] LLM failure in ${context}:`, err);
  if (!invalidKeyNotified) {
    const msg = err instanceof Error ? err.message : String(err);
    if (/401|unauthorized|invalid.?api.?key|authentication/i.test(msg)) {
      invalidKeyNotified = true;
      console.warn('[ARIA] API key appears invalid. Check your key in settings.');
    }
  }
}

/** Returns true if an auth error (401/invalid key) has been detected. */
export function isAuthError(): boolean {
  return invalidKeyNotified;
}

export function initAdvisor(key: string): void {
  apiKey = key;
}

export function getApiKey(): string | null {
  if (apiKey === null) apiKey = loadStoredKey();
  return apiKey;
}

export function hasApiKey(): boolean {
  if (apiKey === null) apiKey = loadStoredKey();
  return apiKey !== null && apiKey.trim().length > 0;
}

async function callLlm(
  systemPrompt: string,
  userMessage: string,
  maxTokens: number = MAX_TOKENS,
  cacheTtlMs: number = DEFAULT_TTL_MS,
  cacheTtlTicks: number = DEFAULT_TTL_TICKS,
  cacheKeyOverride?: string,
): Promise<string> {
  if (!apiKey) throw new Error('No API key');
  const key = cacheKeyOverride ?? makeCacheKey(provider, systemPrompt, userMessage);
  const cached = getCached(key);
  if (cached !== null) return cached;
  const result = await createProvider(provider, apiKey).sendMessage(systemPrompt, userMessage, maxTokens);
  setCached(key, result, cacheTtlMs, cacheTtlTicks);
  // Track usage (cache hits are not counted since no API call was made)
  const inTok = estimateInputTokens(systemPrompt + userMessage);
  const outTok = estimateOutputTokens(result);
  recordUsage(
    provider,
    provider === 'anthropic' ? 'claude-sonnet-4-20250514' : 'openai/gpt-oss-120b', // proxy also uses gpt-oss-120b
    inTok,
    outTok,
  );
  recordSessionUsage(inTok, outTok);
  return result;
}

async function callAdvisorLlm(query: string, gameState: GameStateSummary): Promise<string> {
  const stateContext = serializeGameState(gameState);
  const systemWithContext = `${SYSTEM_PROMPT}\n\nCurrent game state:\n${stateContext}`;
  // Cache key uses bucketed game state hash so minor fluctuations reuse cached responses
  const stateHash = gameStateHash(gameState);
  const cacheKey = makeCacheKey(provider, stateHash, query);
  return callLlm(systemWithContext, query, MAX_TOKENS, DEFAULT_TTL_MS, DEFAULT_TTL_TICKS, cacheKey);
}

export async function askAdvisor(query: string, gameState: GameStateSummary): Promise<string> {
  const now = Date.now();
  const rateLimited = now - lastCallTime < MIN_INTERVAL_MS;
  const tier = determineFallbackTier(hasApiKey(), isOverBudget() || isSessionOverBudget(), rateLimited);

  if (tier !== 'all_clear') {
    // Tiers 1-3: pre-call fallback — return heuristic response
    lastTier = tier;
    return withStatusHint(getGenericFallback(query), tier);
  }

  lastCallTime = now;
  try {
    const result = await withLlmTimeout(callAdvisorLlm(query, gameState));
    lastTier = 'all_clear';
    return result;
  } catch (err) {
    // Tiers 4-5: post-call fallback — classify and return heuristic
    lastTier = classifyError(err);
    warnLlmError('askAdvisor', err);
    return getGenericFallback(query);
  }
}

export async function askAdvisorAboutAnomaly(
  anomalyType: number,
  asteroidEid: number,
  anomalyTypeName: string,
  x: number,
  y: number,
  z: number,
  gameState: GameStateSummary,
): Promise<string> {
  const now = Date.now();
  const rateLimited = now - lastCallTime < MIN_INTERVAL_MS;
  const tier = determineFallbackTier(hasApiKey(), isOverBudget() || isSessionOverBudget(), rateLimited);

  if (tier !== 'all_clear') {
    lastTier = tier;
    return withStatusHint(getAnomalyFallback(anomalyType, asteroidEid), tier);
  }

  lastCallTime = now;
  const query = `A robot just discovered a ${anomalyTypeName} at coordinates (${Math.round(x)}, ${Math.round(y)}, ${Math.round(z)}). What do you make of this?`;

  try {
    const stateContext = serializeGameState(gameState);
    const systemWithContext = `${SYSTEM_PROMPT}\n\nCurrent game state:\n${stateContext}`;
    const result = await withLlmTimeout(callLlm(systemWithContext, query, MAX_TOKENS, ANOMALY_TTL_MS, ANOMALY_TTL_TICKS));
    lastTier = 'all_clear';
    return result;
  } catch (err) {
    lastTier = classifyError(err);
    warnLlmError('askAdvisorAboutAnomaly', err);
    return getAnomalyFallback(anomalyType, asteroidEid);
  }
}

function loadStoredKey(): string | null {
  // Initialize proxy URL from env if available
  const envProxyUrl = import.meta.env?.VITE_PROXY_URL as string | undefined;
  if (envProxyUrl && envProxyUrl.trim().length > 0) {
    setProxyBaseUrl(envProxyUrl.trim());
  }

  // Check URL params for proxy key (e.g. ?proxy_key=xxx)
  if (typeof window !== 'undefined' && window.location) {
    const params = new URLSearchParams(window.location.search);
    const urlProxyKey = params.get('proxy_key');
    if (urlProxyKey && urlProxyKey.trim().length > 0) {
      provider = 'proxy';
      // Persist so it survives page reloads
      if (typeof localStorage !== 'undefined') {
        localStorage.setItem('aria_proxy_key', urlProxyKey.trim());
        localStorage.setItem('aria_provider', 'proxy');
      }
      return urlProxyKey.trim();
    }
  }

  // Check Vite env var first (set via .env file)
  const envProvider = import.meta.env?.VITE_ARIA_PROVIDER as string | undefined;
  if (envProvider && (getRegisteredProviders() as string[]).includes(envProvider)) {
    provider = envProvider as LlmProvider;
  }

  // Heuristic provider doesn't need an API key
  if (provider === 'heuristic') {
    return 'heuristic';
  }

  const envKey = import.meta.env?.VITE_ARIA_API_KEY as string | undefined;
  if (envKey && envKey.trim().length > 0) {
    return envKey.trim();
  }

  if (typeof localStorage === 'undefined' || typeof localStorage.getItem !== 'function')
    return null;
  const storedProvider = localStorage.getItem('aria_provider');
  if (storedProvider && (getRegisteredProviders() as string[]).includes(storedProvider)) {
    provider = storedProvider as LlmProvider;
  }
  // Heuristic provider doesn't need an API key
  if (provider === 'heuristic') {
    return 'heuristic';
  }
  // For proxy provider, use the proxy-specific key or the default shared key
  if (provider === 'proxy') {
    const storedProxyKey = localStorage.getItem('aria_proxy_key');
    if (storedProxyKey) return storedProxyKey;
    // Fall back to build-time default proxy key for new players
    const defaultProxyKey = import.meta.env?.VITE_PROXY_DEFAULT_KEY as string | undefined;
    if (defaultProxyKey && defaultProxyKey.trim().length > 0) return defaultProxyKey.trim();
    return null;
  }
  return localStorage.getItem('aria_api_key');
}

/**
 * Faction diplomacy: ask a faction spokesperson something.
 * Uses the faction's personality as the system prompt.
 */
export async function contactFaction(
  factionPersonality: string,
  playerMessage: string,
  disposition: number,
): Promise<string> {
  const now = Date.now();
  const rateLimited = now - lastCallTime < MIN_INTERVAL_MS;
  const tier = determineFallbackTier(hasApiKey(), isOverBudget() || isSessionOverBudget(), rateLimited);

  if (tier !== 'all_clear') {
    lastTier = tier;
    return withStatusHint(factionFallback(disposition), tier);
  }

  lastCallTime = now;

  const dispositionContext =
    disposition <= -60
      ? 'You are openly hostile to this operation.'
      : disposition <= -20
        ? 'You are wary and suspicious.'
        : disposition <= 20
          ? 'You are neutral and transactional.'
          : disposition <= 60
            ? 'You are friendly but still competitive.'
            : 'You are allied and cooperative.';

  const system = `${factionPersonality}\n\nCurrent disposition toward this mining operation: ${dispositionContext}\n\nRespond in 2-3 sentences, staying in character. You are communicating via encrypted comm channel.`;

  try {
    const result = await withLlmTimeout(callLlm(system, playerMessage, 200));
    lastTier = 'all_clear';
    return result;
  } catch (err) {
    lastTier = classifyError(err);
    warnLlmError('contactFaction', err);
    return factionFallback(disposition);
  }
}

function factionFallback(disposition: number): string {
  if (disposition <= -60)
    return 'Transmission received. We have nothing to say to your operation. Stay out of our sectors.';
  if (disposition <= -20)
    return 'We monitor your activities closely. Do not mistake our silence for opportunity.';
  if (disposition <= 20)
    return 'Message acknowledged. We may have interests that align. Proceed carefully.';
  if (disposition <= 60)
    return 'Your communication is welcome. Let us continue to build on our working relationship.';
  return 'Allies in the void. Your message is received and appreciated. How can we assist?';
}

export function saveApiKey(key: string): void {
  apiKey = key.trim() || null;
  // Reset auth error flag so a new key gets a fresh attempt
  invalidKeyNotified = false;
  if (typeof localStorage !== 'undefined') {
    if (provider === 'proxy') {
      if (apiKey) {
        localStorage.setItem('aria_proxy_key', apiKey);
      } else {
        localStorage.removeItem('aria_proxy_key');
      }
    } else {
      if (apiKey) {
        localStorage.setItem('aria_api_key', apiKey);
      } else {
        localStorage.removeItem('aria_api_key');
      }
    }
  }
}

export function getProvider(): LlmProvider {
  return provider;
}

export function setProvider(p: LlmProvider): void {
  provider = p;
  if (typeof localStorage !== 'undefined') {
    localStorage.setItem('aria_provider', p);
  }
}

export function getAvailableProviders(): LlmProvider[] {
  return getRegisteredProviders();
}
