/**
 * LRU response cache for LLM API calls.
 * Reduces redundant API hits when game state + query are nearly identical.
 *
 * Supports both time-based and tick-based TTL (whichever expires first).
 */

export const DEFAULT_TTL_MS = 60_000; // 60 seconds
export const DEFAULT_TTL_TICKS = 10;
export const ANOMALY_TTL_MS = 30 * 60 * 1000; // 30 minutes — anomalies are discovery-specific
export const ANOMALY_TTL_TICKS = 300; // ~5 minutes of ticks
const MAX_ENTRIES = 50;

interface CacheEntry {
  value: string;
  expiresAt: number;
  /** Tick at which this entry was created. */
  createdAtTick: number;
  /** Maximum tick age before eviction. */
  ttlTicks: number;
}

/** Debug mode — logs cache hits/misses to console when true. */
let debugMode = false;

export function setCacheDebug(enabled: boolean): void {
  debugMode = enabled;
}

/** Current simulation tick — updated externally. */
let currentTick = 0;

export function updateCacheTick(tick: number): void {
  currentTick = tick;
}

export function getCacheTick(): number {
  return currentTick;
}

// Map preserves insertion order; deleting + reinserting moves an entry to "most recent"
const cache = new Map<string, CacheEntry>();

/**
 * djb2 hash — fast, deterministic, good enough for cache keys.
 */
function hashString(s: string): string {
  let h = 5381;
  for (let i = 0; i < s.length; i++) {
    h = (((h << 5) + h) ^ s.charCodeAt(i)) >>> 0;
  }
  return h.toString(36);
}

/**
 * Build a cache key from the inputs that uniquely identify an LLM response.
 * provider + system prompt + user message together capture all variance.
 */
export function makeCacheKey(provider: string, system: string, userMsg: string): string {
  return hashString(`${provider}\x00${system}\x00${userMsg}`);
}

/** Returns the cached value if present and not expired, otherwise null. */
export function getCached(key: string): string | null {
  const entry = cache.get(key);
  if (!entry) {
    if (debugMode) console.debug(`[ARIA cache] MISS (absent) key=${key}`);
    return null;
  }
  // Time-based or tick-based expiry — whichever fires first
  const timeExpired = Date.now() > entry.expiresAt;
  const tickExpired = currentTick - entry.createdAtTick >= entry.ttlTicks;
  if (timeExpired || tickExpired) {
    cache.delete(key);
    if (debugMode) console.debug(`[ARIA cache] MISS (expired: ${timeExpired ? 'time' : 'tick'}) key=${key}`);
    return null;
  }
  // Move to most-recent position (LRU promotion)
  cache.delete(key);
  cache.set(key, entry);
  if (debugMode) console.debug(`[ARIA cache] HIT key=${key}`);
  return entry.value;
}

/** Stores a value in the cache, evicting the LRU entry if at capacity. */
export function setCached(
  key: string,
  value: string,
  ttlMs: number = DEFAULT_TTL_MS,
  ttlTicks: number = DEFAULT_TTL_TICKS,
): void {
  // Evict LRU (first entry) if at capacity
  if (cache.size >= MAX_ENTRIES && !cache.has(key)) {
    const firstKey = cache.keys().next().value;
    if (firstKey !== undefined) cache.delete(firstKey);
  }
  // Overwrite or insert
  cache.delete(key);
  cache.set(key, { value, expiresAt: Date.now() + ttlMs, createdAtTick: currentTick, ttlTicks });
  if (debugMode) console.debug(`[ARIA cache] SET key=${key} ttl=${ttlMs}ms/${ttlTicks}ticks`);
}

/** Clears all cached entries (useful for tests and state resets). */
export function clearCache(): void {
  cache.clear();
}

/** Returns the current number of entries in the cache. */
export function getCacheSize(): number {
  return cache.size;
}
